          <div className="md:hidden bg-off-white pb-4">
            <nav className="flex flex-col items-center space-y-4 pt-2 px-4">
              <a href="#info" onClick={(e) => handleNavClick(e, 'info')} className={buttonStyle}>{content.nav.info}</a>
